// Extract phone number or ticket number from message
const message = $json.message || '';
const phone = $json.phone || '';

// Try to extract identifier from message
// Format: STATUS 081234567890 or STATUS TKT-2026-00123
let identifier = phone; // Default to sender's phone

const parts = message.split(/\s+/);
if (parts.length > 1) {
  // Check if second part looks like phone or ticket number
  const possibleId = parts[1].replace(/[^0-9a-zA-Z-]/g, '');
  if (possibleId.length >= 6) {
    identifier = possibleId;
  }
}

return {
  json: {
    ...$json,
    identifier: identifier
  }
};

// Format status response
const data = $json.data;

const statusEmoji = {
  'menunggu_verifikasi': '⏳',
  'diproses': '🔄',
  'selesai': '✅',
  'ditolak': '❌'
};

const emoji = statusEmoji[data.status] || '📋';

const replyText = `${emoji} *STATUS BERKAS*

📄 No. Tiket: ${data.ticket || '-'}
📋 Jenis: ${data.jenis_layanan || '-'}
📅 Tgl Pengajuan: ${data.tanggal_pengajuan || '-'}

📊 Status: *${data.status?.toUpperCase() || 'TIDAK DIKETAHUI'}*
${data.perkiraan_selesai ? `📅 Perkiraan Selesai: ${data.perkiraan_selesai}` : ''}
${data.catatan ? `\n📝 Catatan: ${data.catatan}` : ''}

💡 Untuk info lebih lanjut, hubungi kantor kecamatan.`;

return {
  json: {
    phone: $('Extract Identifier').item.json.phone,
    chatId: $('Extract Identifier').item.json.chatId,
    reply: replyText
  }
};

// Status not found response
const identifier = $('Extract Identifier').item.json.identifier;

const replyText = `❌ *DATA TIDAK DITEMUKAN*

Tidak ada data dengan identifier: ${identifier}

Pastikan nomor HP atau nomor tiket sudah benar.

💡 Format:
• STATUS 081234567890
• STATUS TKT-2026-00123`;

return {
  json: {
    phone: $('Extract Identifier').item.json.phone,
    chatId: $('Extract Identifier').item.json.chatId,
    reply: replyText
  }
};
